def meny(): 
  """En funktion som skriver ut en meny och frågar användaren om inmatning"""
  print("Meny\n1. Skriv ut en text.\n2. Mata in en text.\n3. Avsluta.") 
  text = "Det var en gång\n" 
  try:
    val = int(input("Vad vill du göra?\n"))
  except ValueError:
    print("Nej, det där var inte ett giligt menyval, vänligen försök igen\n")
    val = int(input("Vad vill du göra?\n"))
  while val != 3: 
    if val == 1: 
      print(text) 
    elif val == 2: 
      text = input("Varsågod och mata in din text: \n")
    val = int(input("Vad vill du göra?\n"))

meny()
